@namespace sv_0d93bf10d95a4f13ad45f59429bb6d57.Components

<div class="file-drop-zone @(_isDragOver ? "drag-over" : "")"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragover:preventDefault
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop"
     @ondrop:preventDefault>
    <InputFile OnChange="OnFilesSelected" multiple class="file-drop-input" />
    <p class="file-drop-prompt">Drag &amp; drop files here, or click to browse</p>
</div>

@if (_entries.Count > 0)
{
    <ul class="file-drop-list">
        @foreach (var entry in _entries)
        {
            <li class="file-drop-entry @(entry.IsError ? "file-drop-error" : "")">
                @if (entry.IsError)
                {
                    <span class="file-error-message">@entry.File.Name — exceeds 10 MB limit (@FormatSize(entry.File.Size))</span>
                }
                else
                {
                    <span class="file-name">@entry.File.Name</span>
                    <span class="file-size">@FormatSize(entry.File.Size)</span>
                    <span class="file-type">@entry.File.Type</span>
                }
                <button class="btn btn-sm btn-danger file-remove-btn" @onclick="() => Remove(entry)">Remove</button>
            </li>
        }
    </ul>
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Forms;

namespace sv_0d93bf10d95a4f13ad45f59429bb6d57.Components;

public partial class FileDropZone : ComponentBase
{
    private const long MaxFileSizeBytes = 10 * 1024 * 1024;

    private bool _isDragOver;
    private readonly List<FileEntry> _entries = new();

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;
        // Actual file handling happens via InputFile's OnChange
        await Task.CompletedTask;
    }

    private async Task OnFilesSelected(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(maximumFileCount: 100))
        {
            var isError = file.Size > MaxFileSizeBytes;
            _entries.Add(new FileEntry(
                new FileInfo(file.Name, file.Size, file.ContentType),
                isError));
        }

        await NotifyParent();
    }

    private async Task Remove(FileEntry entry)
    {
        _entries.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _entries
            .Where(e => !e.IsError)
            .Select(e => e.File)
            .ToList();

        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };

    private sealed record FileEntry(FileInfo File, bool IsError);
}

public record FileInfo(string Name, long Size, string Type);

.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.file-drop-prompt {
    color: #6c757d;
    margin: 0;
    pointer-events: none;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-entry.file-drop-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-error-message {
    color: #dc3545;
    flex: 1;
}

.file-name {
    font-weight: 500;
    flex: 1;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.file-remove-btn {
    margin-left: auto;
}

