.file-drop-zone {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 160px;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    background-color: #f8f9fa;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: pointer;
}

.file-drop-zone.drag-over {
    border-color: #0d6efd;
    background-color: #e7f1ff;
}

.file-drop-prompt {
    color: #6c757d;
    margin: 0;
    pointer-events: none;
}

.file-drop-input {
    position: absolute;
    inset: 0;
    opacity: 0;
    cursor: pointer;
}

.file-drop-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-drop-entry {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-drop-entry.file-drop-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-error-message {
    color: #dc3545;
    flex: 1;
}

.file-name {
    font-weight: 500;
    flex: 1;
}

.file-size,
.file-type {
    color: #6c757d;
    font-size: 0.875rem;
}

.file-remove-btn {
    margin-left: auto;
}

